#!/usr/bin/env python3
"""Block `pnpm test` (interactive vitest watcher); steer Claude to `pnpm test:ci`."""
import json, re, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "").strip()
    if re.match(r"^pnpm\s+test(\s|$)", cmd):
        print(
            "Use `pnpm test:ci` instead. Bare `pnpm test` runs `vitest` in interactive watch mode "
            "and hangs (telemetry shows 3 prior 120s timeouts in this project).",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Enforce CLAUDE.md convention: `pnpm lint` must pass before any `git commit`."""
import json, os, re, subprocess, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not re.search(r"(^|\W)git\s+commit\b", cmd):
        return 0
    cwd = os.environ.get("CLAUDE_PROJECT_DIR") or "."
    try:
        r = subprocess.run(
            ["pnpm", "lint"],
            capture_output=True, text=True, timeout=60, cwd=cwd,
        )
    except Exception as e:
        print(f"lint-before-commit: could not run `pnpm lint` ({e}); allowing commit.", file=sys.stderr)
        return 0
    if r.returncode != 0:
        print("BLOCKING: `pnpm lint` failed. CLAUDE.md requires lint to pass before commit.", file=sys.stderr)
        out = (r.stdout or "")[-1500:]
        err = (r.stderr or "")[-800:]
        if out:
            print(out, file=sys.stderr)
        if err:
            print(err, file=sys.stderr)
        print("Fix the reported lint errors, then retry the commit. Do not bypass with --no-verify.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

