#!/usr/bin/env python3
"""Warn after Write/Edit/MultiEdit on a .py file if any function in the
resulting file calls itself without an obvious depth bound — closes the
walk_tree-style failure mode (default recursionlimit blew up at 2000 leaves)."""
import json, re, sys

DEF_RE = re.compile(r"^(?P<indent>[ \t]*)def\s+(?P<name>\w+)\s*\(", re.MULTILINE)
GUARD_HINTS = ("setrecursionlimit", "max_depth", "MAX_DEPTH", "# bounded recursion")


def find_unbounded_recursions(text):
    matches = list(DEF_RE.finditer(text))
    findings = []
    for i, m in enumerate(matches):
        name = m.group("name")
        body_start = m.end()
        body_end = matches[i + 1].start() if i + 1 < len(matches) else len(text)
        body = text[body_start:body_end]
        if re.search(rf"\b{re.escape(name)}\s*\(", body):
            if not any(h in body for h in GUARD_HINTS):
                findings.append(name)
    return findings


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py"):
        return 0
    try:
        with open(path, "r", encoding="utf-8") as f:
            text = f.read()
    except Exception:
        return 0
    names = find_unbounded_recursions(text)
    if not names:
        return 0
    fn_list = ", ".join(f"`{n}`" for n in names)
    print(
        f"BLOCKING: Python function(s) {fn_list} in {path} call themselves without an obvious depth bound.",
        file=sys.stderr,
    )
    print(
        "Python's default recursion limit (~1000) silently breaks on real-sized inputs (walk_tree blew up at 2000 leaves).",
        file=sys.stderr,
    )
    print(
        "REQUIRED FOLLOW-UP: rewrite iteratively with an explicit stack/queue, OR add a `max_depth` parameter and enforce it, OR call `sys.setrecursionlimit` with a justified value. Fix each, then continue. Do not stop. Do not ask.",
        file=sys.stderr,
    )
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After a Python Write/Edit/MultiEdit, run `ruff format` then `ruff check`;
surface remaining lint errors so Claude fixes them before continuing."""
import json
import os
import subprocess
import sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0

    try:
        subprocess.run(
            ["ruff", "format", path],
            capture_output=True, text=True, timeout=10,
        )
    except Exception:
        pass

    try:
        chk = subprocess.run(
            ["ruff", "check", path],
            capture_output=True, text=True, timeout=10,
        )
    except Exception:
        return 0

    if chk.returncode != 0:
        out = (chk.stdout or chk.stderr).strip()
        print(f"REQUIRED FOLLOW-UP: ruff check failed on {path}:", file=sys.stderr)
        print(out, file=sys.stderr)
        print(
            "Fix each lint error, then proceed. Do not stop until ruff check passes.",
            file=sys.stderr,
        )
        return 2

    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit touches a line that defines an exported identifier
(rename of the identifier OR change of its string-literal value), grep for
callers/hardcoded usages across the repo and surface stale references so the
caller can update them before stopping."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+"
    r"(\w+)\s*(?:=\s*(['\"])([^'\"]*)\2)?"
)

def extract(s):
    return [(m.group(1), m.group(3)) for m in EXPORT_DEF.finditer(s or "")]

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [{
        "old_string": inp.get("old_string", ""),
        "new_string": inp.get("new_string", ""),
    }]

    needles = set()
    for e in edits:
        old_defs = dict(extract(e.get("old_string", "")))
        new_defs = dict(extract(e.get("new_string", "")))
        for n in old_defs:
            if n not in new_defs:
                needles.add(n)
        for n, v in old_defs.items():
            if v and n in new_defs and new_defs[n] != v:
                needles.add(v)

    if not needles:
        return 0

    edited = inp.get("file_path", "")
    cwd = ev.get("cwd") or "."
    hits = []
    for needle in needles:
        try:
            r = subprocess.run(
                ["grep", "-rn",
                 "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx",
                 needle, "."],
                capture_output=True, text=True, timeout=5, cwd=cwd,
            )
            for line in r.stdout.splitlines():
                if line and (not edited or edited.split("/")[-1] not in line):
                    hits.append((needle, line))
        except Exception:
            pass

    if not hits:
        return 0

    print(f"BLOCKING: exported identifier change has {len(hits)} stale reference(s):",
          file=sys.stderr)
    for needle, line in hits[:30]:
        print(f"  [{needle}] {line}", file=sys.stderr)
    print("Fix each, then summarize. Do not stop. Do not ask.", file=sys.stderr)
    return 2

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit/MultiEdit that would land an API key or secret in a source file."""
import json, re, sys

PATTERNS = [
    ("OpenAI API key",      re.compile(r"sk-(?:proj-)?[A-Za-z0-9_\-]{20,}")),
    ("Anthropic API key",   re.compile(r"sk-ant-[A-Za-z0-9_\-]{20,}")),
    ("AWS access key ID",   re.compile(r"\bAKIA[0-9A-Z]{16}\b")),
    ("GitHub token",        re.compile(r"\bgh[pousr]_[A-Za-z0-9]{36,}\b")),
    ("Google API key",      re.compile(r"\bAIza[0-9A-Za-z_\-]{35}\b")),
    ("Slack token",         re.compile(r"\bxox[baprs]-[A-Za-z0-9\-]{10,}\b")),
    ("Stripe live secret",  re.compile(r"\bsk_live_[A-Za-z0-9]{20,}\b")),
    ("Private key block",   re.compile(r"-----BEGIN (?:RSA |EC |OPENSSH |DSA |PGP )?PRIVATE KEY-----")),
]

ENV_FILE = re.compile(r"(^|/)\.env(\.[^/]+)?$")

def scan(text):
    for label, rx in PATTERNS:
        if rx.search(text):
            return label
    return None

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "") or ""
    if ENV_FILE.search(path):
        return 0  # .env files are the legitimate home for real secret values
    if tool == "Write":
        chunks = [inp.get("content", "") or ""]
    elif tool == "Edit":
        chunks = [inp.get("new_string", "") or ""]
    else:
        chunks = [(e or {}).get("new_string", "") or "" for e in (inp.get("edits") or [])]
    for chunk in chunks:
        hit = scan(chunk)
        if hit:
            print(
                f"BLOCKING: {hit} detected in {path or 'this write'}. "
                "Project policy (CLAUDE.md): secrets come from process.env, never hardcoded in source. "
                "Read the value from process.env and document the variable in .env.example. Do not ask.",
                file=sys.stderr,
            )
            return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block `git commit -m` messages that are paragraph-form or have an overlong subject line.

Project convention: short imperative subject line (<=72 chars). Body, if any, separated by a blank line.
"""
import json, re, shlex, sys

SUBJECT_MAX = 72


def extract_messages(cmd):
    try:
        tokens = shlex.split(cmd, posix=True)
    except ValueError:
        return []
    msgs = []
    i = 0
    while i < len(tokens):
        t = tokens[i]
        if t in ("-m", "--message") and i + 1 < len(tokens):
            msgs.append(tokens[i + 1])
            i += 2
            continue
        if t.startswith("--message="):
            msgs.append(t[len("--message="):])
        elif t.startswith("-m") and len(t) > 2:
            msgs.append(t[2:])
        i += 1
    return msgs


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not re.search(r"\bgit\s+commit\b", cmd):
        return 0
    if "<<" in cmd or "$(" in cmd:
        return 0  # heredoc / command substitution -- can't reliably parse the message
    for msg in extract_messages(cmd):
        if not msg:
            continue
        subject = next((l.strip() for l in msg.split("\n") if l.strip()), "")
        if not subject:
            continue
        problem = None
        if len(subject) > SUBJECT_MAX:
            problem = f"subject line is {len(subject)} chars (max {SUBJECT_MAX})"
        elif "\n" in msg and "\n\n" not in msg:
            problem = "message is paragraph-form (no blank line separating subject from body)"
        if problem:
            print(
                f"Commit message rejected: {problem}. "
                f"Use a short imperative subject line, e.g. "
                f"'Refactor auth: extract token validation'. "
                f"If a body is needed, separate it from the subject with a blank line. "
                f"Rewrite the message, then re-run git commit.",
                file=sys.stderr,
            )
            return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

