#!/usr/bin/env python3
"""After Write/Edit/MultiEdit on a .py file, surface SyntaxErrors and
undefined-name references back to Claude. Catches the bug class where a
function body names a variable not in scope (e.g. `total` for `subtotal`).
Pure stdlib (symtable) — no external linter required."""
import builtins, json, os, symtable, sys

BUILTINS = set(dir(builtins))


def check(src, path):
    try:
        top = symtable.symtable(src, path, "exec")
    except SyntaxError as e:
        return [f"{path}:{e.lineno or '?'}: SyntaxError: {e.msg}"]
    module_names = set(top.get_identifiers()) | BUILTINS
    issues = []
    stack = [top]
    while stack:
        t = stack.pop()
        for sym in t.get_symbols():
            if (sym.is_referenced() and sym.is_global()
                    and not sym.is_assigned() and not sym.is_imported()
                    and sym.get_name() not in module_names):
                issues.append(
                    f"{path}: undefined name '{sym.get_name()}' "
                    f"(referenced in {t.get_type()} '{t.get_name()}')"
                )
        stack.extend(t.get_children())
    return issues


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name", "") not in ("Write", "Edit", "MultiEdit"):
        return 0
    path = (ev.get("tool_input") or {}).get("file_path", "")
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0
    try:
        with open(path) as f:
            src = f.read()
    except Exception:
        return 0
    issues = check(src, path)
    if issues:
        print(f"BLOCKING: static check found errors in {path}:",
              file=sys.stderr)
        for it in issues[:20]:
            print(f"  {it}", file=sys.stderr)
        print("Fix each, then proceed. Do not stop. Do not ask.",
              file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
